// [#extension: envoy.filters.http.custom_header_injection]

message Config {
  option (udpa.annotations.versioning).previous_message_type =
      "envoy.config.filter.http.custom_header_injection.v3.Config";

  // Headers to inject into all requests passing through the filter.
  // The header names will be converted to lowercase and the values will be set as-is.
