// [#protodoc-title: Custom Header Injection Filter]
//
// The configuration for injecting custom headers into requests and responses.
// This filter allows you to add or overwrite HTTP headers based on static configuration.
//
// Custom Header Injection :ref:`configuration overview <config_http_filters_custom_header_injection>`.
// [#extension: envoy.filters.http.custom_header_injection]

message Config {
  option (udpa.annotations.versioning).previous_message_type =
      "envoy.config.filter.http.custom_header_injection.v3.Config";

  // Headers to inject into all requests passing through the filter.
  // The header names will be converted to lowercase and the values will be set as-is.
  // If a header is already present, it will be overwritten.
  map<string, string> request_headers = 1;

  // Headers to inject into all responses passing through the filter.
  // The header names will be converted to lowercase and the values will be set as-is.
  // If a header is already present, it will be overwritten.
  map<string, string> response_headers = 2;
}
